import anthropic, json

client = anthropic.Anthropic()

# Known task categories for this agent
IN_DISTRIBUTION_CATEGORIES = {
    "refund_request", "order_status", "shipping_update",
    "product_question", "address_change",
}

def classify_ticket(ticket: str) -> dict:
    """
    Classify a ticket before routing it to the agent.
    If the category is out-of-distribution, escalate rather than attempting.
    Returns: {category: str, in_distribution: bool, confidence: str}
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=128,
        messages=[{
            "role": "user",
            "content": (
                f"Classify this customer support ticket into one category.\n"
                f"Known categories: {sorted(IN_DISTRIBUTION_CATEGORIES)}\n"
                f"If it doesn't fit any known category, use 'unknown'.\n"
                f"Ticket: {ticket}\n"
                f"Return JSON: {{"category": str, "confidence": "high|medium|low"}}"
            ),
        }],
    )
    result = json.loads(response.content[0].text)
    result["in_distribution"] = result["category"] in IN_DISTRIBUTION_CATEGORIES
    return result


def routed_support_agent(ticket: str, agent_fn, escalate_fn) -> str:
    """
    Route ticket through classifier before agent.
    Out-of-distribution inputs escalate to human; in-distribution inputs go to agent.
    """
    classification = classify_ticket(ticket)

    if not classification["in_distribution"] or classification["confidence"] == "low":
        print(f"[ESCALATE] Category: {classification['category']}, confidence: {classification['confidence']}")
        return escalate_fn(ticket, reason=f"out-of-distribution: {classification['category']}")

    return agent_fn(ticket)
